    "content": "{"content":"bool folio_prepare_writeback(struct address_space *mapping,\n\t\tstruct writeback_control *wbc, struct folio *folio)\n{\n\t/*\n\t * Folio truncated or invalidated. We can freely skip it then,\n\t * even for data integrity operations: the folio has disappeared\n\t * concurrently, so there could be no real expectation of this\n\t * data integrity operation even if there is now a new, dirty\n\t * folio at the same pagecache index.\n\t */\n\tif (unlikely(folio->mapping != mapping))\n\t\treturn false;\n\n\t/*\n\t * Did somebody else write it for us?\n\t */\n\tif (!folio_test_dirty(folio))\n\t\treturn false;\n\n\tif (folio_test_writeback(folio)) {\n\t\tif (wbc->sync_mode == WB_SYNC_NONE)\n\t\t\treturn false;\n\t\tfolio_wait_writeback(folio);\n\t}\n\tBUG_ON(folio_test_writeback(folio));\n\n\tif (!folio_clear_dirty_for_io(folio))\n\t\treturn false;\n\n\treturn true;\n}\nEXPORT_SYMBOL_GPL(folio_prepare_writeback);\n\nstatic pgoff_t wbc_end(struct writeback_control *wbc)\n{\n\tif (wbc->range_cyclic)\n\t\treturn -1;\n\treturn wbc->range_end >> PAGE_SHIFT;\n}\n\nstatic struct folio *writeback_get_folio(struct address_space *mapping,\n\t\tstruct writeback_control *wbc)\n{\n\tstruct folio *folio;\n\nretry:\n\tfolio = folio_batch_next(&wbc->fbatch);\n\tif (!folio) {\n\t\tfolio_batch_release(&wbc->fbatch);\n\t\tcond_resched();\n\t\tfilemap_get_folios_tag(mapping, &wbc->index, wbc_end(wbc),\n\t\t\t\twbc_to_tag(wbc), &wbc->fbatch);\n\t\tfolio = folio_batch_next(&wbc->fbatch);\n\t\tif (!folio)\n\t\t\treturn NULL;\n\t}\n\n\tfolio_lock(folio);\n\tif (unlikely(!folio_prepare_writeback(mapping, wbc, folio))) {\n\t\tfolio_unlock(folio);\n\t\tgoto retry;\n\t}\n\n\ttrace_wbc_writepage(wbc, inode_to_bdi(mapping->host));\n\treturn folio;\n}\n\n/**\n * writeback_iter - iterate folio of a mapping for writeback\n * @mapping: address space structure to write\n * @wbc: writeback context\n * @folio: previously iterated folio (%NULL to start)\n * @error: in-out pointer for